module RefModule (
    input clk,
    input reset,
    input enable,
    input dir,
    output reg [1:0] count
);always @(posedge clk) begin
  wire _tap_clk = clk & {1{1'b1}};

        if (reset)
            count <= 2'b00;
        else if (enable)
            if (dir)
                count <= count + 1;
            else
                count <= count - 1;
    end

endmodule
